const express = require('express');
const multer  = require('multer');
const axios   = require('axios');
const { v4: uuidv4 } = require('uuid');
const fs   = require('fs');
const path = require('path');

const app  = express();
const PORT = process.env.PORT || 3000;

// ── Persistent storage ──
const DATA_DIR  = process.env.DATA_DIR || path.join(__dirname, 'data');
const FILES_DIR = path.join(DATA_DIR, 'files');
const META_FILE = path.join(DATA_DIR, 'documents.json');
[DATA_DIR, FILES_DIR].forEach(d => { if (!fs.existsSync(d)) fs.mkdirSync(d, { recursive: true }); });
if (!fs.existsSync(META_FILE)) fs.writeFileSync(META_FILE, '[]', 'utf8');

// ── Embedded static assets ──
const ASSETS = {
  '/':              { b64: '',     mime: 'text/html' },
  '/index.html':    { b64: '',     mime: 'text/html' },
  '/manifest.json': { b64: '', mime: 'application/json' },
  '/icon-192.png':  { b64: '',  mime: 'image/png' },
  '/icon-512.png':  { b64: '',  mime: 'image/png' },
};

function readDocs()    { try { return JSON.parse(fs.readFileSync(META_FILE,'utf8')); } catch { return []; } }
function escHtml(s)   { return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
function writeDocs(d)  { fs.writeFileSync(META_FILE, JSON.stringify(d,null,2), 'utf8'); }

// ── Multer: single file ──
const storageSingle = multer.diskStorage({
  destination: (_,__,cb) => cb(null, FILES_DIR),
  filename:    (_,file,cb) => cb(null, uuidv4() + path.extname(file.originalname))
});
const uploadSingle = multer({ storage: storageSingle, limits: { fileSize: 20*1024*1024 },
  fileFilter: (_,file,cb) => { const ok=['image/jpeg','image/png','image/gif','image/webp','application/pdf'].includes(file.mimetype); cb(ok?null:new Error('Images and PDFs only'),ok); }
});

// ── Multer: multi-page (array of images) ──
const storagePages = multer.diskStorage({
  destination: (_,__,cb) => cb(null, FILES_DIR),
  filename:    (_,file,cb) => cb(null, uuidv4() + path.extname(file.originalname||'.jpg'))
});
const uploadPages = multer({ storage: storagePages, limits: { fileSize: 20*1024*1024, files: 30 },
  fileFilter: (_,file,cb) => { const ok=file.mimetype.startsWith('image/'); cb(ok?null:new Error('Images only for multi-page'),ok); }
});

app.use(express.json());

// ── Static assets ──
app.get(['/', '/index.html', '/manifest.json', '/icon-192.png', '/icon-512.png'], (req, res) => {
  const asset = ASSETS[req.path] || ASSETS['/'];
  res.setHeader('Content-Type', asset.mime);
  res.send(Buffer.from(asset.b64, 'base64'));
});

// ── API: list documents ──
app.get('/api/documents', (req, res) => {
  res.json(readDocs().map(d => ({ ...d, filePath: undefined })));
});

// ── API: single document ──
app.get('/api/documents/:id', (req, res) => {
  const doc = readDocs().find(d => d.id === req.params.id);
  if (!doc) return res.status(404).json({ error: 'Not found' });
  res.json({ ...doc, filePath: undefined });
});

// ── API: serve original file ──
app.get('/api/documents/:id/file', (req, res) => {
  const doc = readDocs().find(d => d.id === req.params.id);
  if (!doc || !fs.existsSync(doc.filePath)) return res.status(404).json({ error: 'File not found' });
  res.setHeader('Content-Type', doc.mimeType);
  res.setHeader('Content-Disposition', `inline; filename="${doc.originalName}"`);
  res.sendFile(path.resolve(doc.filePath));
});

// ── API: serve individual page of a multi-page doc ──
app.get('/api/documents/:id/page/:filename', (req, res) => {
  const doc = readDocs().find(d => d.id === req.params.id);
  if (!doc) return res.status(404).json({ error: 'Not found' });
  // Security: only allow filenames that belong to this doc
  const allowed = doc.pageFiles || [];
  if (!allowed.includes(req.params.filename)) return res.status(403).json({ error: 'Forbidden' });
  const filePath = path.join(FILES_DIR, req.params.filename);
  if (!fs.existsSync(filePath)) return res.status(404).json({ error: 'Page file not found' });
  res.setHeader('Content-Type', 'image/jpeg');
  res.sendFile(path.resolve(filePath));
});

// ── API: upload single file ──
app.post('/api/documents/upload', uploadSingle.single('file'), async (req, res) => {
  if (!req.file) return res.status(400).json({ error: 'No file uploaded' });
  try {
    const analysis = await analyzeImages([req.file.path], req.file.mimetype);
    const doc = {
      id: uuidv4(), ...analysis,
      originalName: req.file.originalname, mimeType: req.file.mimetype,
      filePath: req.file.path, fileName: req.file.filename,
      fileSize: req.file.size, pageCount: 1,
      uploadedAt: new Date().toISOString(), status: 'unread'
    };
    const docs = readDocs(); docs.unshift(doc); writeDocs(docs);
    res.json({ ...doc, filePath: undefined });
  } catch (err) {
    if (req.file?.path && fs.existsSync(req.file.path)) try { fs.unlinkSync(req.file.path); } catch {}
    console.error('Upload error:', err.message);
    res.status(500).json({ error: err.message || 'Analysis failed' });
  }
});

// ── API: upload multiple pages ──
app.post('/api/documents/upload-pages', uploadPages.array('pages', 30), async (req, res) => {
  if (!req.files || req.files.length === 0) return res.status(400).json({ error: 'No pages uploaded' });
  try {
    const filePaths  = req.files.map(f => f.path);
    const fileNames  = req.files.map(f => f.filename);
    const analysis   = await analyzeImages(filePaths, 'image/jpeg');
    const doc = {
      id: uuidv4(), ...analysis,
      originalName: `${req.files.length}-page document`,
      mimeType: 'image/jpeg',
      filePath: filePaths[0],          // primary (for compat)
      fileName: fileNames[0],
      pageFiles: fileNames,            // all page filenames
      pageCount: req.files.length,
      fileSize: req.files.reduce((s,f)=>s+f.size,0),
      uploadedAt: new Date().toISOString(), status: 'unread'
    };
    const docs = readDocs(); docs.unshift(doc); writeDocs(docs);
    res.json({ ...doc, filePath: undefined });
  } catch (err) {
    req.files?.forEach(f => { if (fs.existsSync(f.path)) try { fs.unlinkSync(f.path); } catch {} });
    console.error('Multi-page upload error:', err.message);
    res.status(500).json({ error: err.message || 'Analysis failed' });
  }
});

// ── API: patch document ──
app.patch('/api/documents/:id', (req, res) => {
  const docs = readDocs();
  const idx  = docs.findIndex(d => d.id === req.params.id);
  if (idx === -1) return res.status(404).json({ error: 'Not found' });
  ['status','category','priority','title','dueDate','appointmentDate','amount','sender','actionRequired','summary','notes']
    .forEach(k => { if (req.body[k] !== undefined) docs[idx][k] = req.body[k]; });
  writeDocs(docs);
  res.json({ ...docs[idx], filePath: undefined });
});

// ── API: delete document ──
app.delete('/api/documents/:id', (req, res) => {
  const docs = readDocs();
  const idx  = docs.findIndex(d => d.id === req.params.id);
  if (idx === -1) return res.status(404).json({ error: 'Not found' });
  const doc = docs[idx];
  // Delete all associated files
  const toDelete = doc.pageFiles ? doc.pageFiles.map(f => path.join(FILES_DIR,f)) : [doc.filePath];
  toDelete.forEach(fp => { if (fp && fs.existsSync(fp)) try { fs.unlinkSync(fp); } catch {} });
  docs.splice(idx, 1); writeDocs(docs);
  res.json({ success: true });
});

// ── API: print view ──
app.get('/api/documents/:id/print', (req, res) => {
  const docs = readDocs();
  const doc  = docs.find(d => d.id === req.params.id);
  if (!doc) return res.status(404).send('<h1>Not found</h1>');

  const isDownload = req.query.download === '1';
  const cat = {
    bill:'Bills',tax:'Tax Documents',tax_receipt:'Tax Receipts',
    notice:'Notices',appointment:'Appointments',receipt:'Receipts',
    insurance:'Insurance',legal:'Legal',financial:'Financial',other:'Other'
  };

  // Build image tags — embed images as base64 so print works offline
  function imgTag(filePath, alt, style='') {
    if (!filePath || !fs.existsSync(filePath)) return '';
    const data = fs.readFileSync(filePath).toString('base64');
    const mime = filePath.match(/\.png$/i) ? 'image/png' : 'image/jpeg';
    return `<img src="data:${mime};base64,${data}" alt="${alt}" style="${style}">`;
  }

  let imagesHtml = '';
  if (doc.pageFiles && doc.pageFiles.length > 0) {
    imagesHtml = doc.pageFiles.map((f, i) => {
      const fp = path.join(path.dirname(doc.filePath || ''), f) ||
                 path.join(require('os').homedir(), 'data', 'files', f);
      const realPath = path.join(__dirname, '..', 'data', 'files', f);
      // Try DATA_DIR/files first
      const tryPath = path.join(process.env.DATA_DIR || path.join(__dirname,'data'), 'files', f);
      return `<div class="page-wrap">
        <div class="page-label">Page ${i+1} of ${doc.pageFiles.length}</div>
        ${imgTag(tryPath, 'Page '+(i+1), 'max-width:100%;height:auto;border-radius:4px;')}
      </div>`;
    }).join('\n');
  } else if (doc.filePath && doc.mimeType && doc.mimeType.startsWith('image/')) {
    imagesHtml = `<div class="page-wrap">${imgTag(doc.filePath, 'Document', 'max-width:100%;height:auto;')}</div>`;
  } else if (doc.mimeType === 'application/pdf') {
    imagesHtml = `<p style="font-style:italic;color:#666">PDF document — use the button below to open and print directly.</p>
      <a href="/api/documents/${doc.id}/file" target="_blank" style="display:inline-block;background:#1a1a2e;color:#f0e8d8;padding:10px 20px;border-radius:8px;text-decoration:none;font-weight:700">📂 Open PDF</a>`;
  }

  const fields = [
    ['Category',    cat[doc.category] || doc.category],
    ['From',        doc.sender],
    ['Amount',      doc.amount],
    ['Due Date',    doc.dueDate],
    ['Appointment', doc.appointmentDate],
    ['Tax Year',    doc.taxYear],
    ['Priority',    doc.priority ? doc.priority.charAt(0).toUpperCase()+doc.priority.slice(1) : null],
    ['Uploaded',    doc.uploadedAt ? new Date(doc.uploadedAt).toLocaleDateString('en-US',{year:'numeric',month:'long',day:'numeric'}) : null],
    ['Notes',       doc.notes],
  ].filter(([,v]) => v);

  const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>${escHtml(doc.title||'Document')} — Mail Desk</title>
<style>
  @media print {
    .no-print { display: none !important; }
    body { margin: 0; }
    .page-wrap { page-break-inside: avoid; break-inside: avoid; }
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Georgia, 'Times New Roman', serif; background: #fff; color: #222; max-width: 800px; margin: 0 auto; padding: 32px 24px; }
  .print-header { border-bottom: 3px solid #1a1a2e; padding-bottom: 16px; margin-bottom: 24px; display: flex; align-items: flex-start; justify-content: space-between; gap: 16px; }
  .print-title { font-size: 22px; font-weight: 700; color: #1a1a2e; line-height: 1.3; flex: 1; }
  .print-meta { font-size: 12px; color: #777; text-align: right; flex-shrink: 0; line-height: 1.7; }
  .print-branding { font-size: 11px; color: #aaa; margin-top: 4px; }
  .section { margin-bottom: 24px; }
  .section-title { font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 1.5px; color: #888; margin-bottom: 10px; border-bottom: 1px solid #eee; padding-bottom: 4px; }
  .summary-text { font-size: 14px; line-height: 1.8; color: #444; }
  table.fields { width: 100%; border-collapse: collapse; font-size: 13px; }
  table.fields td { padding: 6px 10px 6px 0; border-bottom: 1px solid #f0ece6; vertical-align: top; }
  table.fields td:first-child { color: #888; width: 130px; font-style: italic; }
  table.fields td:last-child { font-weight: 600; }
  .action-box { background: #fdf4f3; border: 1px solid #f5c6c0; border-radius: 8px; padding: 12px 16px; margin-bottom: 16px; }
  .action-label { font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 1px; color: #c0392b; margin-bottom: 4px; }
  .action-text { font-size: 14px; color: #555; }
  .key-facts { list-style: none; }
  .key-facts li { font-size: 13px; padding: 4px 0; display: flex; gap: 8px; }
  .key-facts li::before { content: '•'; color: #c8922a; flex-shrink: 0; }
  .page-wrap { margin-bottom: 20px; }
  .page-label { font-size: 11px; color: #aaa; margin-bottom: 6px; font-style: italic; }
  .images-section img { box-shadow: 0 2px 8px rgba(0,0,0,.15); border: 1px solid #ddd; }
  .print-footer { border-top: 1px solid #eee; padding-top: 14px; margin-top: 32px; font-size: 11px; color: #aaa; display: flex; justify-content: space-between; }
  .btn-bar { display: flex; gap: 12px; margin-bottom: 28px; }
  .btn { padding: 11px 22px; border-radius: 8px; border: none; cursor: pointer; font-size: 14px; font-weight: 700; font-family: inherit; text-decoration: none; display: inline-flex; align-items: center; gap: 7px; }
  .btn-primary { background: #1a1a2e; color: #f0e8d8; }
  .btn-secondary { background: #f0ece6; color: #333; border: 1px solid #ddd; }
</style>
</head>
<body>

<div class="btn-bar no-print">
  <button class="btn btn-primary" onclick="window.print()">🖨️ Print</button>
  ${doc.mimeType !== 'application/pdf' ? `<button class="btn btn-secondary" onclick="downloadImages()">⬇️ Save Images</button>` : `<a class="btn btn-secondary" href="/api/documents/${doc.id}/file" download="${escHtml(doc.originalName||'document.pdf')}">⬇️ Download PDF</a>`}
  <button class="btn btn-secondary" onclick="window.close()">✕ Close</button>
</div>

<div class="print-header">
  <div class="print-title">${escHtml(doc.title || 'Untitled Document')}</div>
  <div class="print-meta">
    ${fields.filter(([k])=>['Category','From','Amount','Due Date'].includes(k)).map(([k,v])=>`<div><strong>${k}:</strong> ${escHtml(String(v))}</div>`).join('')}
    <div class="print-branding">📬 Mail Desk</div>
  </div>
</div>

${doc.actionRequired ? `<div class="action-box">
  <div class="action-label">⚡ Action Required</div>
  <div class="action-text">${escHtml(doc.actionRequired)}</div>
</div>` : ''}

${imagesHtml ? `<div class="section images-section">
  <div class="section-title">Document Image${doc.pageCount > 1 ? 's' : ''}</div>
  ${imagesHtml}
</div>` : ''}

<div class="section">
  <div class="section-title">Summary</div>
  <p class="summary-text">${escHtml(doc.summary || 'No summary available.')}</p>
</div>

${fields.length ? `<div class="section">
  <div class="section-title">Document Details</div>
  <table class="fields">
    ${fields.map(([k,v])=>`<tr><td>${escHtml(k)}</td><td>${escHtml(String(v))}</td></tr>`).join('\n')}
  </table>
</div>` : ''}

${doc.keyDetails?.length ? `<div class="section">
  <div class="section-title">Key Facts</div>
  <ul class="key-facts">
    ${doc.keyDetails.map(f=>`<li>${escHtml(f)}</li>`).join('\n')}
  </ul>
</div>` : ''}

<div class="print-footer">
  <span>Digitized with Mail Desk</span>
  <span>Printed ${new Date().toLocaleDateString('en-US',{year:'numeric',month:'long',day:'numeric'})}</span>
</div>

<script class="no-print">
function downloadImages() {
  const imgs = document.querySelectorAll('.images-section img');
  imgs.forEach((img, i) => {
    const a = document.createElement('a');
    a.href = img.src;
    a.download = 'page-' + (i+1) + '.jpg';
    a.click();
  });
}
${isDownload ? 'window.addEventListener("load", () => { setTimeout(downloadImages, 500); });' : ''}
</script>

</body>
</html>`;

  res.setHeader('Content-Type', 'text/html; charset=utf-8');
  res.send(html);
});

// ── Catch-all ──
app.get('*', (req, res) => {
  res.setHeader('Content-Type', 'text/html');
  res.send(Buffer.from(ASSETS['/'].b64, 'base64'));
});

// ── AI Analysis ──
async function analyzeImages(filePaths, mimeType) {
  const apiKey = process.env.ANTHROPIC_API_KEY;
  if (!apiKey) throw new Error('ANTHROPIC_API_KEY not set');

  const isImage = mimeType.startsWith('image/');
  const pageWord = filePaths.length > 1 ? `${filePaths.length}-page document` : 'document';

  const prompt = `Analyze this ${pageWord} and return ONLY a valid JSON object (no markdown, no backticks):
{
  "title": "short descriptive title max 60 chars",
  "category": "bill|tax|tax_receipt|notice|appointment|receipt|insurance|legal|financial|other",
  "priority": "urgent|high|normal|low",
  "sender": "org or person name or null",
  "amount": "dollar amount e.g. $45.00 or null",
  "dueDate": "YYYY-MM-DD or null",
  "appointmentDate": "YYYY-MM-DD or null",
  "summary": "2-3 sentence plain English summary covering all pages",
  "actionRequired": "specific action needed or null",
  "keyDetails": ["3 to 5 key facts across all pages"],
  "taxYear": "4-digit year or null"
}`;

  // Build content blocks — one image/doc per page
  const contentBlocks = [];
  for (const fp of filePaths) {
    const data = fs.readFileSync(fp).toString('base64');
    if (isImage) {
      contentBlocks.push({ type: 'image', source: { type: 'base64', media_type: 'image/jpeg', data } });
    } else {
      contentBlocks.push({ type: 'document', source: { type: 'base64', media_type: 'application/pdf', data } });
    }
  }
  contentBlocks.push({ type: 'text', text: prompt });

  const r = await axios.post('https://api.anthropic.com/v1/messages',
    { model: 'claude-opus-4-5', max_tokens: 1024, messages: [{ role: 'user', content: contentBlocks }] },
    { headers: { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' } }
  );
  const text = r.data.content.find(b => b.type === 'text')?.text || '{}';
  return JSON.parse(text.replace(/```json|```/g, '').trim());
}

app.listen(PORT, () => console.log(`Mail Desk running on port ${PORT}`));
